  akali: { diff: "TRICKY", tone: "#ff8b3d", tldr: "AP brawl \u2014 build MR, W-poke off shroud, E-root.", breakdown: "Both AP. Build MR, W-poke her off her shroud, and E-root her all-in.", dos: ["Build MR", "W-poke off her shroud", "E-root her all-in"], donts: ["Fight her in the shroud", "Stand still for her combo", "Get Q-poked down"], key: { slot: "W", name: "Twilight Shroud", cd: "18s", note: "Untargetable inside. Poke when down.", winT: "SHROUD DOWN", winS: "E-root + R her." }, hold: "Hold E to root her all-in \u2014 the root catches her even through shroud if you predict it; then R-drain.", tip: "Both AP \u2014 build MR, W-poke her off her shroud, and E-root her all-in.", win: "Build MR and E-root her all-in." },
