  quinn: { diff: "EVEN", tone: "#e8b84b", tldr: "Poke war \u2014 E-root her vault, build MR.", breakdown: "W-poke from range, E-root her vault, and build MR vs her poke.", dos: ["W-poke from range", "E-root her vault", "Build MR vs her poke"], donts: ["Fight into her blind", "Let her kite you out", "Get caught with E down"], key: { slot: "E", name: "Vault (Dash/Blind)", cd: "11s", note: "Her self-peel. Root out of it.", winT: "VAULT DOWN", winS: "E-root + R her." }, hold: "Hold E to root her when she vaults in \u2014 lock her down and R-drain her.", tip: "W-poke from range, E-root her vault, and build MR vs her poke.", win: "W-poke + E-root her vault." },
  rumble: { diff: "EVEN", tone: "#e8b84b", tldr: "AP brawl \u2014 build MR, W-poke, E-root, dodge his R.", breakdown: "Both AP. Build MR, W-poke from range, E-root his engage, and dodge his R line.", dos: ["Build MR", "W-poke from range", "Dodge his R line"], donts: ["Extend into his danger-zone Q", "Stand in his R line", "Fight in his flamespitter"], key: { slot: "W", name: "Scrap Shield", cd: "6s", note: "Bait it, then commit.", winT: "SHIELD DOWN", winS: "E-root + R him." }, hold: "Hold E to root him out of his engage \u2014 build MR; W-poke and dodge his R.", tip: "Both AP \u2014 build MR, W-poke from range, E-root his engage, and dodge his Equalizer.", win: "Build MR and E-root his engage." },
