  swain: { diff: "MIRROR", tone: "#e8b84b", tldr: "Swain mirror \u2014 whoever lands E-root + W first and out-drains wins.", breakdown: "Pure Swain mirror: it\u2019s a W-poke and E-root race. Whoever lands the root + W combo first and out-drains wins.", dos: ["Win the W poke war", "Land E-root first", "Out-drain with R"], donts: ["Get E-rooted first", "Fight into his R drain", "Fall behind in farm"], key: { slot: "E", name: "Nevermove (Root)", cd: "10s", note: "Whoever lands E-root + W first wins.", winT: "ROOT DOWN", winS: "E-root + R him." }, hold: "Hold E to root him first \u2014 whoever lands the E-root + W combo and out-drains with R wins.", tip: "It\u2019s a W-poke and E-root mirror \u2014 win the poke war, land E-root first, and out-drain with R.", win: "Land E-root first and out-drain him." },
